sys_script_include.script:
function CreatePrintableQRCodesPDF(vQRCode)
{
	var RecordAttachmentDeleteByFileName = x_snc_devtools.RecordAttachmentDeleteByFileName;
	var CreatePDFFromHtml = x_snc_devtools.CreatePDFFromHtml;
	var GetRecord = x_snc_devtools.GetRecord;
	var IsValidRecord = x_snc_devtools.IsValidRecord;

	var grQRCode = GetRecord('x_snc_qrcode_qrcode',vQRCode);
	if (IsValidRecord(grQRCode) == false)
	{
		return false;
	} 


	var strHtml = '<html><head></head><body>';
	strHtml += HtmlRenderPrintableQRCodesA4(grQRCode); 
	strHtml += '</body></html>';

	var strFileName = 'qrcode_' + grQRCode.sys_id+'.pdf';

	x_snc_devtools.RecordAttachmentDeleteByFileName(
		'x_snc_qrcode_qrcode',
		grQRCode.sys_id,
		strFileName);	

	var vResult = x_snc_devtools.CreatePDFFromHtml(
		'x_snc_qrcode_qrcode',
		grQRCode.sys_id,
		strFileName,
		strHtml,
		'A4',
		'PORTRAIT',
		0,0,
		false)

	return vResult;


}
